from functools import *
@lru_cache(None)

def g(h):
m = [h+1, h+3, h*2]
if h >= 39: return "win"
if any(g(x) == "win" for x in m): return "p1"
if all(g(x) == "p1" for x in m): return "v1"
if any(g(x) == "v1" for x in m): return "p2"
if all(g(x) == "p1" or g(x) == "p2" for x in m): return "v2"

v1, p2, v2 = [], [], []
for h in range(38, 0, -1):
if g(h) == "v1": v1.append(h)
if g(h) == "p2": p2.append(h)
if g(h) == "v2": v2.append(h)

print("19: ", *v1)
print("20: ", *sorted(p2))
print("21: ", min(v2))
